for(const p of professions){const title=`Taxes for ${p.name}`;const desc=`A practical tax-planning guide for ${p.name.toLowerCase()}, covering income, expenses, records, reserves, and relevant calculators.`;const body=header('Profession tax guide',title,`Organize the financial side of ${p.name.toLowerCase()} work without assuming every cost qualifies or every payment follows the same tax treatment.`)+`<section class="section prose"><h2>Who this guide is for</h2><p>This guide is for people earning independent-business income through ${p.income.join(', ')}. Entity structure, worker classification, location, and other facts can change the analysis.</p><h2>Common income sources</h2>${links(p.income,'',x=>x).replaceAll('href="'+p.income[0]+'/"','href="#"').replace(/<a href="[^"]+">/g,'<span>').replaceAll('</a>','</span>')}<h2>Expense categories to review</h2><p>Potentially relevant categories include ${p.expenses.join(', ')}. A cost must be evaluated under current rules; personal portions, reimbursements, inventory, and capital assets may receive different treatment.</p><h2>Records worth gathering</h2><p>${esc(p.records)}. Record the business purpose rather than relying only on a merchant name or bank feed.</p></section><aside class="ad-slot content-ad" aria-label="Advertisement placeholder"><span>Advertisement</span></aside><section class="section prose"><h2>Self-employment tax and quarterly planning</h2><p>Start with supported net business profit, not gross deposits. Self-employment tax is distinct from federal income tax. Withholding, credits, W-2 wages, filing status, and household facts can affect the broader projection.</p><h2>Build a tax reserve</h2><p>A reserve is cash planning, not a filed payment or safe-harbor determination. Revisit it when income or expenses change, especially when this work is seasonal or uneven.</p><h2>Hypothetical example</h2><p><strong>Example:</strong> ${esc(p.example)} The example illustrates organization only and is not a taxpayer outcome.</p><h2>Common mistakes</h2><ul><li>Failing to reconcile  with invoices, platform statements, or deposits.</li><li>Treating every  cost as business-only without reviewing personal use.</li><li>Assuming an expense produces a dollar-for-dollar refund.</li><li>Waiting until filing season to reconcile this profession’s work records and payments.</li></ul><h2>When professional help may be appropriate</h2><p>Consider qualified help for entity choices, workers, inventory, depreciation, multistate work, amended records, classification questions, or facts that do not fit the calculators.</p></section><section class="section split"><div><h2>Relevant calculators</h2>${links(p.calcs,'../../calculators/',x=>calcNames[x])}</div><div><h2>Expense guides</h2>${links(p.deds,'../../deductions/',x=>deductions.find(d=>d.slug===x)?.title||x)}</div></section><section class="section split"><div><h2>Tax education</h2>${links(['what-is-self-employment-tax','how-to-save-for-quarterly-taxes','what-records-should-independent-contractors-keep'],'../',x=>education.find(g=>g.slug===x)?.title||x)}</div><div><h2>Related professions</h2>${links(p.related,'../taxes-for-',x=>professions.find(q=>q.slug===x)?.name||x)}</div></section>${sources()}${disclaimer}`;write(`guides/taxes-for-${p.slug}/index.html`,shell(`guides/taxes-for-${p.slug}/`,title,desc,body));}

for(let index=0;index<education.length;index+=1){const g=education[index],detail=educationDetail[g.slug],related=[education[(index+1)%education.length].slug,education[(index+2)%education.length].slug,education[(index+education.length-1)%education.length].slug],professionSet=g.slug.includes('mileage')?['rideshare-drivers','delivery-drivers','real-estate-agents']:g.slug.includes('home-office')?['consultants','web-developers','graphic-designers']:g.slug.includes('rate')||g.slug.includes('contractor-charge')?['freelancers','consultants','software-developers']:g.slug.includes('income')?['freelancers','content-creators','online-sellers']:['freelancers','independent-contractors','gig-workers'];const body=header('1099 tax education',g.title,g.desc)+`<section class="section prose"><h2>Plain-language introduction</h2><p>${esc(g.desc)} This guide separates general planning concepts from facts and tax-year rules that need current official verification.</p><h2>Why this matters for 1099 workers</h2><p>${esc(detail.why)}</p><h2>Step-by-step explanation</h2><ol>${detail.steps.map(x=>`<li>${esc(x)}</li>`).join('')}</ol><h2>Key ideas</h2><ul>${g.points.map(x=>`<li>${esc(x)}</li>`).join('')}</ul><h2>Hypothetical example</h2><p><strong>Hypothetical example:</strong> ${esc(g.example)} This illustration is not an actual taxpayer outcome or a promise of tax treatment.</p></section><aside class="ad-slot content-ad" aria-label="Advertisement placeholder"><span>Advertisement</span></aside><section class="section prose"><h2>Common mistakes</h2><ul>${g.mistakes.map(x=>`<li>${esc(x)}</li>`).join('')}<li>Using an old tax-year value or deadline without checking the current official source.</li></ul><h2>What this guide does not cover</h2><p>This guide does not calculate every credit, deduction, special tax, state or local rule, accounting method, entity rule, penalty exception, or eligibility limitation. It does not prepare or file a return.</p><h2>When professional help may be appropriate</h2><p>Qualified help may be useful for multiple businesses, employees or subcontractors, inventory, depreciation, entity elections, multistate work, amended records, large income changes, notices, or facts that do not fit the linked calculators.</p><h2>Records to gather</h2><p>Use invoices, payment statements, receipts, mileage or workspace records where relevant, prior returns, withholding statements, contracts, and estimated-payment confirmations.</p></section><section class="section split"><div><h2>Related calculators</h2>${links(detail.calcs,'../../calculators/',x=>calcNames[x])}</div><div><h2>Related profession guides</h2>${links(professionSet,'../taxes-for-',x=>professions.find(p=>p.slug===x).name)}</div></section><section class="section split"><div><h2>Related deduction guides</h2>${links(['software-and-subscriptions','vehicle-expenses','home-office-expenses'],'../../deductions/',x=>deductions.find(d=>d.slug===x).title)}</div><div><h2>Related educational guides</h2>${links(related,'../',x=>education.find(y=>y.slug===x).title)}</div></section>${sources(`, ${detail.source}`)}${disclaimer}`;write(`guides/${g.slug}/index.html`,shell(`guides/${g.slug}/`,g.title,g.desc,body));}

for(let index=0;index<deductions.length;index+=1){const d=deductions[index],detail=deductionDetail[d.slug],related=[deductions[(index+1)%deductions.length].slug,deductions[(index+2)%deductions.length].slug,deductions[(index+deductions.length-1)%deductions.length].slug],title=`${d.title} for Self-Employed Work`,desc=`Learn what ${d.title.toLowerCase()} may include, how mixed use and reimbursements affect planning, which records help, and what may need special treatment.`;const body=header('Business expense guide',title,`Use this guide to organize potentially relevant costs while keeping personal use, eligibility, reimbursement, and timing limitations visible.`)+`<section class="section prose"><h2>What this category generally includes</h2><p>${esc(d.covers)} may qualify when the facts establish an appropriate business connection and current requirements are met.</p><h2>Potentially relevant business expenses</h2><ul>${detail.examples.map(x=>`<li>${esc(x)}</li>`).join('')}</ul><p>These are organizational examples, not a determination that a particular cost is deductible.</p><h2>Personal-use and mixed-use considerations</h2><p>${esc(detail.mixed)} A reasonable allocation needs records that explain the chosen business percentage.</p><h2>Reimbursement considerations</h2><p>${esc(detail.reimburse)} Spending and reimbursement should not be used to claim the same economic cost twice.</p><h2>Recordkeeping suggestions</h2><p>${esc(detail.records)}</p></section><aside class="ad-slot content-ad" aria-label="Advertisement placeholder"><span>Advertisement</span></aside><section class="section prose"><h2>Expenses requiring special treatment</h2><p>${esc(detail.special)}</p><h2>Capitalization and depreciation warning</h2><p>Long-lived property, improvements, acquired intangible rights, prepaid costs, and other capital items may not receive the same current treatment as routine operating costs. This guide does not calculate depreciation, amortization, basis, or an expensing election.</p><h2>Eligibility limitations</h2><p>Eligibility depends on the complete facts, applicable tax year, entity, business purpose, personal use, reimbursement, timing, and current instructions. The site cannot determine legal deductibility.</p><h2>Hypothetical example</h2><p><strong>Hypothetical example:</strong> ${esc(d.example)} The example illustrates record organization and does not promise eligibility or tax savings.</p><h2>Common mistakes</h2><ul><li>Assuming every ${esc(detail.examples[0])} payment qualifies without reviewing business purpose.</li><li>Claiming a personal, reimbursed, or mixed-use amount in full.</li><li>Keeping only a bank description instead of supporting purpose and treatment.</li><li>Assuming a $1,000 expense normally creates a $1,000 refund; a deduction generally reduces an income measure rather than reimbursing the purchase price.</li></ul></section><section class="section split"><div><h2>Related calculators</h2>${links(detail.calcs,'../../calculators/',x=>calcNames[x])}</div><div><h2>Related profession guides</h2>${links(detail.profs,'../../guides/taxes-for-',x=>professions.find(p=>p.slug===x).name)}</div></section><section class="section split"><div><h2>Related educational guides</h2>${links(detail.edu,'../../guides/',x=>education.find(g=>g.slug===x).title)}</div><div><h2>Related deduction categories</h2>${links(related,'../',x=>deductions.find(y=>y.slug===x).title)}</div></section>${sources(`, ${detail.source}`)}${disclaimer}`;write(`deductions/${d.slug}/index.html`,shell(`deductions/${d.slug}/`,title,desc,body));}

const card=(href,title,desc,best)=>`<a class="link-card filter-item" data-search="${esc(`${title} ${desc} ${best}`.toLowerCase())}" href="${href}"><p class="eyebrow">Best for: ${esc(best)}</p><h3>${esc(title)}</h3><p>${esc(desc)}</p><span>Read guide &rarr;</span></a>`;
