const guideBody=`<header class="page-head"><p class="eyebrow">Educational library</p><h1>1099 tax guides</h1><p class="lede">Find a focused explanation, profession guide, or recordkeeping workflow and continue to a relevant calculator.</p></header><div class="card directory-filter"><label for="guideFilter"><strong>Filter guides</strong></label><input id="guideFilter" type="search" placeholder="Try mileage, freelancer, records, or quarterly tax" aria-describedby="guideFilterHelp"><p class="hint" id="guideFilterHelp">Results update as you type. No search information leaves your browser.</p><p class="fine" id="filterStatus" aria-live="polite"></p></div><section class="section"><h2>Getting started</h2><div class="card-grid">${education.slice(0,7).map(g=>card(g.slug+'/',g.title,g.desc,'Getting started')).join('')}</div></section><section class="section"><h2>Income and pricing</h2><div class="card-grid">${education.slice(13,17).map(g=>card(g.slug+'/',g.title,g.desc,'Income and pricing')).join('')}</div></section><section class="section"><h2>Expenses, deductions, and records</h2><div class="card-grid">${education.slice(7,13).concat(education.slice(17)).map(g=>card(g.slug+'/',g.title,g.desc,'Expense and record planning')).join('')}</div></section><section class="section" id="profession-guides"><h2>Profession guides</h2><div class="card-grid">${professions.map(p=>card(`taxes-for-${p.slug}/`,`Taxes for ${p.name}`,`Income, expense, recordkeeping, and reserve considerations for ${p.name.toLowerCase()}.`,'Profession-specific planning')).join('')}</div></section><section class="notice"><h2>Start with numbers</h2><p><a href="../calculators/">Choose a calculator</a> after gathering the records described in these guides.</p></section>`;write('guides/index.html',directoryShell('guides/','1099 Tax Guides','Browse practical guides about self-employment tax, quarterly payments, deductions, records, pricing, and profession-specific planning.',guideBody));
