let home=fs.readFileSync(path.join(root,'index.html'),'utf8');const start='<!-- phase5-discovery:start -->',end='<!-- phase5-discovery:end -->';const featured=['freelancers','independent-contractors','rideshare-drivers','consultants','real-estate-agents','content-creators','online-sellers','personal-trainers'];const block=`${start}<section class="section"><div class="section-heading"><div><p class="eyebrow">Tax guides by profession</p><h2>Connect your work patterns to the right tools</h2></div><p>Start with records and expense categories that fit how you actually earn.</p></div><div class="card-grid">${featured.map(s=>{const p=professions.find(x=>x.slug===s);return `<a class="link-card" href="guides/taxes-for-${s}/"><h3>${p.name}</h3><p>${p.income.slice(0,2).join(' and ')}, with tailored calculator paths.</p><span>Read profession guide &rarr;</span></a>`}).join('')}</div><div class="button-row"><a class="button secondary" href="guides/">Browse all profession guides</a><a class="button secondary" href="deductions/">Browse deduction guides</a></div></section><section class="band"><h2>New tax education</h2><p>Learn how self-employment tax, estimated payments, records, and deductions fit together, then use a calculator to test your own planning inputs.</p><a href="guides/what-is-self-employment-tax/">Start with self-employment tax &rarr;</a></section>${end}`;if(home.includes(start))home=home.replace(new RegExp(`${start}[\\s\\S]*?${end}`),block);else home=home.replace('<section class="notice"><h2>Important tax disclaimer</h2>',block+'<section class="notice"><h2>Important tax disclaimer</h2>');write('index.html',home);

